frame_eqs:
basstime = basstime + bass*0.06;
q1 = basstime;

basstime = if(below(bass,1),basstime,basstime - time*0.5);

vol = pow(bass+mid+treb,2);
basssum = vol;

stickybit = time%2;

//avg vol
//buffer 1: most recent 4 beats
buf4 = if(equal(buffer4,0),vol,if(equal(buffer3,0),vol,if(equal(buffer2,0),vol,if(equal(buffer1,0),vol,buffer4))));
//buffer 2: 1/4th of most recent beat
buf2 = if(equal(buffer4,0),buf4,if(equal(buffer3,0),buf3,if(equal(buffer2,0),buf2,if(equal(buffer1,0),buf1,buffer2))));
//buffer 3: 3/4ths of most recent beat
buf3 = if(equal(buffer4,0),buf3,if(equal(buffer3,0),buf3,if(equal(buffer2,0),buf2,if(equal(buffer1,0),buf1,buffer3))));
//buffer 4: avg of past 4 buffers
buf4 = if(equal(buffer4,0),buf4,if(equal(buffer3,0),buf3,if(equal(buffer2,0),buf2,if(equal(buffer1,0),buf1,buffer4))));

//take difference of vol and buffer 4, divide by buffer 4 (beat detection)
diff = (vol - buf4)/buf4;
//boolean beat? / avg vol
beat = if(above(abs(diff),0.15),if(above(avg,2),avg/buf4*1.6,basssum/4),0);
//flag 1 frame for beat
beathard = if(above(beat,0),if(below(beathard,1),1,beathard-beat),beathard);

//count how many frames had a beat
btcount = if(above(beathard,0),btcount+1,btcount);
//take difference of frame rate and 60, divide by 60 (fps detection)
difftime = (time - basstime)/basstime;
//boolean slow frame? / avg fps
slowframe = if(above(abs(difftime),0.15),if(above(avgfps,60),avgfps/60,fps),0);
//flag 1 frame for slow frame
sfhard = if(above(slowframe,0),if(below(sfhard,1),1,sfhard-slowframe),sfhard);

//count how many frames had a beat
btcount = if(above(beathard,0),btcount+1,btcount);
//count how many frames were slow
sfcount = if(above(sfhard,0),sfcount+1,sfcount);

//transision between states
//0: normal state
//1: beat state
//2: slow frame state
//3: error state (both 1 and 2)

//if currently in beat state, change to normal state after 3 frames
state = if(equal(state,1),if(equal(btcount,3),0,state),state);
//if currently in slow frame state, change to normal state after 3 frames
state = if(equal(state,2),if(equal(sfcount,3),0,state),state);
//if currently in error state, change to normal state after 50 frames
state = if(equal(state,3),if(equal(btcount+sfcount,50),0,state),state);

//if in normal state, check for beats or slowframes and change states
state = if(equal(state,0),if(above(beat,0),1,if(above(slowframe,0),2,if((below(beat,0)*below(slowframe,0)),0,state))),state);

//output state for possible other uses
q2 = state;

//beep during beat state
if(above(state,0)*below(state,2),bass_att,bass);

